import React from 'react';
import ReactDOM from 'react-dom';
import {BrowserRouter as Router} from 'react-router-dom';
import App from './App';
import './styles/index.scss'

ReactDOM.render(
  <React.StrictMode>
    <RouterRouter>
          <App />
      </RouterRouter>
  </React.StrictMode>,
document.getElementById('root')
);
